using AiVideoStudio.Domain.Base;using AiVideoStudio.Domain.Enums;
namespace AiVideoStudio.Domain.Entities;
public sealed class WorkflowExecution:BaseEntity
{public string WorkflowId{get;private set;}=string.Empty;public WorkflowStatus Status{get;private set;}=WorkflowStatus.Running;public DateTimeOffset StartedAt{get;private set;}public DateTimeOffset? CompletedAt{get;private set;}public Dictionary<string,string> OutputContext{get;private set;}=new();public string? Error{get;private set;}private WorkflowExecution(){}public static WorkflowExecution Start(string workflowId,string owner)=>new(){WorkflowId=workflowId,StartedAt=DateTimeOffset.UtcNow,CreatedAt=DateTimeOffset.UtcNow,CreatedBy=owner};public void Complete(IDictionary<string,string> output){Status=WorkflowStatus.Completed;OutputContext=new(output);CompletedAt=DateTimeOffset.UtcNow;}public void Fail(string error){Status=WorkflowStatus.Failed;Error=error;CompletedAt=DateTimeOffset.UtcNow;}public void Cancel(){Status=WorkflowStatus.Cancelled;CompletedAt=DateTimeOffset.UtcNow;}}
